		{
			if (!NodeValueEquals(a.CollectionItems[i], b.CollectionItems[i]))
				return false;
		}

		return true;
	}

	/// <summary>Recursively compares two ListNodes for equality.</summary>
	static bool ListNodeEquals(ListNode a, ListNode b)
	{
		if (a.CollectionItems.Count != b.CollectionItems.Count)
			return false;

		for (int i = 0; i < a.CollectionItems.Count; i++)
		{
			if (!NodeValueEquals(a.CollectionItems[i], b.CollectionItems[i]))
				return false;
		}

		return true;
	}

	static bool XmlTypeEquals(XmlType a, XmlType b) =>
		a.Name == b.Name && a.NamespaceUri == b.NamespaceUri && TypeArgumentsEqual(a.TypeArguments, b.TypeArguments);

	static bool TypeArgumentsEqual(IList<XmlType>? a, IList<XmlType>? b)
	{
		if (a is null && b is null) return true;
		if (a is null || b is null) return false;
		if (a.Count != b.Count) return false;
		for (int i = 0; i < a.Count; i++)
		{
			if (!XmlTypeEquals(a[i], b[i]))
				return false;
		}
		return true;
	}

	static bool StringEquals(string? a, string? b) =>
		string.Equals(a, b, StringComparison.Ordinal);

	/// <summary>
	/// Builds a stable child node ID by combining the parent path and the child's type + sibling index.
	/// </summary>
	static string ChildNodeId(string parentId, string childTypeName, int index)
		=> string.IsNullOrEmpty(parentId)
			? $"{childTypeName}_{index}"
			: $"{parentId}/{childTypeName}_{index}";

	/// <summary>
	/// Returns a string key that uniquely identifies an <see cref="XmlType"/> including its
	/// namespace, name, and type arguments. Used for matching children by type during reorder detection.
	/// </summary>
	static string TypeSignature(XmlType type)
	{
		if (type.TypeArguments == null || type.TypeArguments.Count == 0)
			return string.Concat(type.NamespaceUri, ":", type.Name);

		var sb = new System.Text.StringBuilder();
		sb.Append(type.NamespaceUri).Append(':').Append(type.Name).Append('<');
		for (int i = 0; i < type.TypeArguments.Count; i++)
		{
			if (i > 0) sb.Append(',');
			sb.Append(TypeSignature(type.TypeArguments[i]));
		}
		sb.Append('>');
		return sb.ToString();
	}
}
